package org.apache.beam.sdk.options;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

/**
 * Holds the result of validating {@link PipelineOptions} via {@link PipelineOptionsValidator.Builder}.
 *
 * <p>A {@link ValidationResult} accumulates errors and warnings produced during validation. Use
 * {@link #isValid()} to check whether any errors were found, and {@link #getErrors()} /
 * {@link #getWarnings()} to retrieve individual messages.
 */
public class ValidationResult {

  private final List<String> errors;
  private final List<String> warnings;

  ValidationResult(List<String> errors, List<String> warnings) {
    this.errors = Collections.unmodifiableList(new ArrayList<>(errors));
    this.warnings = Collections.unmodifiableList(new ArrayList<>(warnings));
  }

  /** Returns {@code true} if no validation errors were found. */
  public boolean isValid() {
    return errors.isEmpty();
  }

  /** Returns an unmodifiable list of validation error messages. */
  public List<String> getErrors() {
    return errors;
  }

  /** Returns an unmodifiable list of validation warning messages. */
  public List<String> getWarnings() {
    return warnings;
  }

  @Override
  public String toString() {
    return "ValidationResult{errors=" + errors + ", warnings=" + warnings + "}";
  }
}

