    org.junit.Assert.assertTrue(result.getErrors().isEmpty());
  }

  @Test
  public void testBuilderValidateRequiredFailsWhenValueMissing() {
    SimpleOptions opts = PipelineOptionsFactory.as(SimpleOptions.class);
    opts.setRunner(CrashingRunner.class);
