    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateType("getName", String.class)
            .validate(opts);

    org.junit.Assert.assertTrue(result.isValid());
  }

  @Test
  public void testBuilderValidateRangePassesWhenInRange() {
    SimpleOptions opts = PipelineOptionsFactory.as(SimpleOptions.class);
    opts.setRunner(CrashingRunner.class);
    opts.setCount(5);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRange("getCount", 1, 10)
            .validate(opts);

    org.junit.Assert.assertTrue(result.isValid());
  }

  @Test
  public void testBuilderValidateRangeFailsWhenOutOfRange() {
    SimpleOptions opts = PipelineOptionsFactory.as(SimpleOptions.class);
    opts.setRunner(CrashingRunner.class);
    opts.setCount(100);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRange("getCount", 1, 10)
            .validate(opts);

    org.junit.Assert.assertFalse(result.isValid());
    org.junit.Assert.assertFalse(result.getErrors().isEmpty());
  }

  @Test
  public void testBuilderAccumulatesMultipleErrors() {
    SimpleOptions opts = PipelineOptionsFactory.as(SimpleOptions.class);
    opts.setRunner(CrashingRunner.class);
    opts.setCount(100);
    // name not set

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRequired("getName")
            .validateRange("getCount", 1, 10)
            .validate(opts);

    org.junit.Assert.assertFalse(result.isValid());
    org.junit.Assert.assertEquals(2, result.getErrors().size());
  }
