33: /** Validates that the {@link PipelineOptions} conforms to all the {@link Validation} criteria. */
34: @SuppressWarnings({
35:   "nullness" // TODO(https://github.com/apache/beam/issues/20497)
36: })
37: public class PipelineOptionsValidator {
38:   /**
39:    * Validates that the passed {@link PipelineOptions} conforms to all the validation criteria from
40:    * the passed in interface.
41:    *
42:    * <p>Note that the interface requested must conform to the validation criteria specified on
43:    * {@link PipelineOptions#as(Class)}.
44:    *
45:    * @param klass The interface to fetch validation criteria from.
46:    * @param options The {@link PipelineOptions} to validate.
47:    * @return Validated options.
48:    */
49:   public static <T extends PipelineOptions> T validate(Class<T> klass, PipelineOptions options) {
50:     return validate(klass, options, false);
51:   }
52: 
53:   /**
54:    * Validates that the passed {@link PipelineOptions} from command line interface (CLI) conforms to
55:    * all the validation criteria from the passed in interface.
56:    *
57:    * <p>Note that the interface requested must conform to the validation criteria specified on
58:    * {@link PipelineOptions#as(Class)}.
59:    *
60:    * @param klass The interface to fetch validation criteria from.
61:    * @param options The {@link PipelineOptions} to validate.
62:    * @return Validated options.
63:    */
64:   public static <T extends PipelineOptions> T validateCli(Class<T> klass, PipelineOptions options) {
65:     return validate(klass, options, true);
66:   }
67: 
68:   private static <T extends PipelineOptions> T validate(
69:       Class<T> klass, PipelineOptions options, boolean isCli) {
70:     checkNotNull(klass);
71:     checkNotNull(options);
72:     checkArgument(Proxy.isProxyClass(options.getClass()));
73:     checkArgument(Proxy.getInvocationHandler(options) instanceof ProxyInvocationHandler);
74: 
75:     // Ensure the methods for T are registered on the ProxyInvocationHandler
76:     T asClassOptions = options.as(klass);
77: 
78:     ProxyInvocationHandler handler =
79:         (ProxyInvocationHandler) Proxy.getInvocationHandler(asClassOptions);
80: 
81:     SortedSetMultimap<String, Method> requiredGroups =
82:         TreeMultimap.create(
83:             Ordering.natural(), PipelineOptionsFactory.MethodNameComparator.INSTANCE);
84:     for (Method method : ReflectHelpers.getClosureOfMethodsOnInterface(klass)) {
85:       Required requiredAnnotation = method.getAnnotation(Validation.Required.class);
86:       if (requiredAnnotation != null) {
87:         if (requiredAnnotation.groups().length > 0) {
88:           for (String requiredGroup : requiredAnnotation.groups()) {
89:             requiredGroups.put(requiredGroup, method);
90:           }
91:         } else {
92:           if (isCli) {
93:             checkArgument(
94:                 handler.invoke(asClassOptions, method, null) != null,
95:                 "Missing required value for [--%s, \"%s\"]. ",
96:                 handler.getOptionName(method),
97:                 getDescription(method));
98:           } else {
99:             checkArgument(
100:                 handler.invoke(asClassOptions, method, null) != null,
101:                 "Missing required value for [%s, \"%s\"]. ",
102:                 method,
103:                 getDescription(method));
104:           }
105:         }
106:       }
107:     }
108: 
109:     for (String requiredGroup : requiredGroups.keySet()) {
110:       if (!verifyGroup(handler, asClassOptions, requiredGroups.get(requiredGroup))) {
111:         throw new IllegalArgumentException(
112:             "Missing required value for group ["
113:                 + requiredGroup
114:                 + "]. At least one of the following properties "
115:                 + Collections2.transform(
116:                     requiredGroups.get(requiredGroup), ReflectHelpers::formatMethod)
117:                 + " required. Run with --help="
118:                 + klass.getSimpleName()
119:                 + " for more information.");
120:       }
121:     }
122: 
123:     return asClassOptions;
124:   }
125: 
126:   private static boolean verifyGroup(
127:       ProxyInvocationHandler handler, PipelineOptions options, Collection<Method> requiredGroup) {
128:     for (Method m : requiredGroup) {
129:       if (handler.invoke(options, m, null) != null) {
130:         return true;
131:       }
132:     }
133:     return false;
134:   }
135: 
136:   private static String getDescription(Method method) {
137:     Description description = method.getAnnotation(Description.class);
138:     return description == null ? "" : description.value();
139:   }
140: }
