package org.apache.beam.sdk.options;

import static org.apache.beam.vendor.guava.v32_1_2_jre.com.google.common.base.Preconditions.checkArgument;
import static org.apache.beam.vendor.guava.v32_1_2_jre.com.google.common.base.Preconditions.checkNotNull;

import java.lang.reflect.Method;
import java.lang.reflect.Proxy;
import java.util.ArrayList;
import java.util.Collection;
import java.util.List;
import org.apache.beam.sdk.options.Validation.Required;
import org.apache.beam.sdk.util.common.ReflectHelpers;
import org.apache.beam.vendor.guava.v32_1_2_jre.com.google.common.collect.Collections2;
import org.apache.beam.vendor.guava.v32_1_2_jre.com.google.common.collect.Ordering;
import org.apache.beam.vendor.guava.v32_1_2_jre.com.google.common.collect.SortedSetMultimap;
import org.apache.beam.vendor.guava.v32_1_2_jre.com.google.common.collect.TreeMultimap;

/** Validates that the {@link PipelineOptions} conforms to all the {@link Validation} criteria. */
@SuppressWarnings({
  "nullness" // TODO(https://github.com/apache/beam/issues/20497)
})
public class PipelineOptionsValidator {

  // -------------------------------------------------------------------------
  // Existing static API (preserved for backward compatibility)
  // -------------------------------------------------------------------------

  /**
   * Validates that the passed {@link PipelineOptions} conforms to all the validation criteria from
   * the passed in interface.
   *
   * <p>Note that the interface requested must conform to the validation criteria specified on {@link
   * PipelineOptions#as(Class)}.
   *
   * @param klass The interface to fetch validation criteria from.
   * @param options The {@link PipelineOptions} to validate.
   * @return Validated options.
   */
  public static <T extends PipelineOptions> T validate(Class<T> klass, PipelineOptions options) {
    return validateInternal(klass, options, false);
  }

  /**
   * Validates that the passed {@link PipelineOptions} from command line interface (CLI) conforms to
   * all the validation criteria from the passed in interface.
   *
   * <p>Note that the interface requested must conform to the validation criteria specified on {@link
   * PipelineOptions#as(Class)}.
   *
   * @param klass The interface to fetch validation criteria from.
   * @param options The {@link PipelineOptions} to validate.
   * @return Validated options.
   */
  public static <T extends PipelineOptions> T validateCli(
      Class<T> klass, PipelineOptions options) {
    return validateInternal(klass, options, true);
  }

  private static <T extends PipelineOptions> T validateInternal(
      Class<T> klass, PipelineOptions options, boolean isCli) {
    checkNotNull(klass);
    checkNotNull(options);
    checkArgument(Proxy.isProxyClass(options.getClass()));
    checkArgument(Proxy.getInvocationHandler(options) instanceof ProxyInvocationHandler);

    // Ensure the methods for T are registered on the ProxyInvocationHandler
    T asClassOptions = options.as(klass);

    ProxyInvocationHandler handler =
        (ProxyInvocationHandler) Proxy.getInvocationHandler(asClassOptions);

    SortedSetMultimap<String, Method> requiredGroups =
        TreeMultimap.create(
            Ordering.natural(), PipelineOptionsFactory.MethodNameComparator.INSTANCE);
    for (Method method : ReflectHelpers.getClosureOfMethodsOnInterface(klass)) {
      Required requiredAnnotation = method.getAnnotation(Validation.Required.class);
      if (requiredAnnotation != null) {
        if (requiredAnnotation.groups().length > 0) {
          for (String requiredGroup : requiredAnnotation.groups()) {
            requiredGroups.put(requiredGroup, method);
          }
        } else {
          if (isCli) {
            checkArgument(
                handler.invoke(asClassOptions, method, null) != null,
                "Missing required value for [--%s, \"%s\"]. ",
                handler.getOptionName(method),
                getDescription(method));
          } else {
            checkArgument(
                handler.invoke(asClassOptions, method, null) != null,
                "Missing required value for [%s, \"%s\"]. ",
                method,
                getDescription(method));
          }
        }
      }
    }

    for (String requiredGroup : requiredGroups.keySet()) {
      if (!verifyGroup(handler, asClassOptions, requiredGroups.get(requiredGroup))) {
        throw new IllegalArgumentException(
            "Missing required value for group ["
                + requiredGroup
                + "]. At least one of the following properties "
                + Collections2.transform(
                    requiredGroups.get(requiredGroup), ReflectHelpers::formatMethod)
                + " required. Run with --help="
                + klass.getSimpleName()
                + " for more information.");
      }
    }

    return asClassOptions;
  }

  private static boolean verifyGroup(
      ProxyInvocationHandler handler, PipelineOptions options, Collection<Method> requiredGroup) {
    for (Method m : requiredGroup) {
      if (handler.invoke(options, m, null) != null) {
        return true;
      }
    }
    return false;
  }

  private static String getDescription(Method method) {
    Description description = method.getAnnotation(Description.class);
    return description == null ? "" : description.value();
  }

  // -------------------------------------------------------------------------
  // Builder-based API for accumulating validation rules
  // -------------------------------------------------------------------------

  /** Creates a new {@link Builder} for constructing a rule-based validator. */
  public static Builder builder() {
    return new Builder();
  }

  /**
   * A builder that accumulates validation rules and produces a {@link ValidationResult} when {@link
   * #validate(PipelineOptions)} is called.
   */
  public static class Builder {

    /** Represents a single validation rule applied to a {@link PipelineOptions} instance. */
    @FunctionalInterface
    interface ValidationRule {
      void apply(PipelineOptions options, List<String> errors, List<String> warnings);
    }

    private final List<ValidationRule> rules = new ArrayList<>();

    private Builder() {}

    /**
     * Adds a rule that verifies the named option is non-null on the given options object.
     *
     * @param optionName the getter method name (e.g. {@code "getRunner"})
     * @return this builder
     */
    public Builder validateRequired(String optionName) {
      checkNotNull(optionName, "optionName must not be null");
      rules.add(
          (options, errors, warnings) -> {
            try {
              Method getter = findGetter(options, optionName);
              Object value = getter.invoke(options);
              if (value == null) {
                errors.add("Missing required value for option: " + optionName);
              }
            } catch (NoSuchMethodException e) {
              errors.add("Unknown option: " + optionName);
            } catch (ReflectiveOperationException e) {
              errors.add("Error reading option '" + optionName + "': " + e.getMessage());
            }
          });
      return this;
    }

    /**
     * Adds a rule that verifies the named option's value is an instance of {@code expectedType}.
     *
     * @param optionName the getter method name (e.g. {@code "getRunner"})
     * @param expectedType the expected runtime type of the option value
     * @return this builder
     */
    public Builder validateType(String optionName, Class<?> expectedType) {
      checkNotNull(optionName, "optionName must not be null");
      checkNotNull(expectedType, "expectedType must not be null");
      rules.add(
          (options, errors, warnings) -> {
            try {
              Method getter = findGetter(options, optionName);
              Object value = getter.invoke(options);
              if (value != null && !expectedType.isInstance(value)) {
                errors.add(
                    "Option '"
                        + optionName
                        + "' expected type "
                        + expectedType.getName()
                        + " but got "
                        + value.getClass().getName());
              }
            } catch (NoSuchMethodException e) {
              errors.add("Unknown option: " + optionName);
            } catch (ReflectiveOperationException e) {
              errors.add("Error reading option '" + optionName + "': " + e.getMessage());
            }
          });
      return this;
    }

    /**
     * Adds a rule that verifies the named option's value falls within [{@code min}, {@code max}]
     * (inclusive). The option value must implement {@link Comparable}.
     *
     * @param optionName the getter method name (e.g. {@code "getParallelism"})
     * @param min the minimum allowed value (inclusive)
     * @param max the maximum allowed value (inclusive)
     * @param <C> the comparable type
     * @return this builder
     */
    @SuppressWarnings({"unchecked", "rawtypes"})
    public <C extends Comparable<C>> Builder validateRange(String optionName, C min, C max) {
      checkNotNull(optionName, "optionName must not be null");
      checkNotNull(min, "min must not be null");
      checkNotNull(max, "max must not be null");
      rules.add(
          (options, errors, warnings) -> {
            try {
              Method getter = findGetter(options, optionName);
              Object value = getter.invoke(options);
              if (value == null) {
                return; // null check is handled by validateRequired
              }
              if (!(value instanceof Comparable)) {
                errors.add(
                    "Option '"
                        + optionName
                        + "' value does not implement Comparable; cannot validate range.");
                return;
              }
              Comparable comparable = (Comparable) value;
              if (comparable.compareTo(min) < 0 || comparable.compareTo(max) > 0) {
                errors.add(
                    "Option '"
                        + optionName
                        + "' value "
                        + value
                        + " is out of range ["
                        + min
                        + ", "
                        + max
                        + "].");
              }
            } catch (NoSuchMethodException e) {
              errors.add("Unknown option: " + optionName);
            } catch (ReflectiveOperationException e) {
              errors.add("Error reading option '" + optionName + "': " + e.getMessage());
            }
          });
      return this;
    }

    /**
     * Runs all accumulated validation rules against the supplied {@link PipelineOptions} and
     * returns a {@link ValidationResult} that contains any errors or warnings.
     *
     * @param options the options to validate
     * @return the result of running all accumulated rules
     */
    public ValidationResult validate(PipelineOptions options) {
      checkNotNull(options, "options must not be null");
      List<String> errors = new ArrayList<>();
      List<String> warnings = new ArrayList<>();
      for (ValidationRule rule : rules) {
        rule.apply(options, errors, warnings);
      }
      return new ValidationResult(errors, warnings);
    }

    // -----------------------------------------------------------------------
    // Helpers
    // -----------------------------------------------------------------------

    /**
     * Finds the getter method with the given name on the concrete class of {@code options}.
     * Searches all interfaces implemented by the proxy as well.
     */
    private static Method findGetter(PipelineOptions options, String methodName)
        throws NoSuchMethodException {
      // Try the concrete (proxy) class first, then walk through interfaces.
      Class<?> cls = options.getClass();
      for (Class<?> iface : cls.getInterfaces()) {
        try {
          return iface.getMethod(methodName);
        } catch (NoSuchMethodException ignored) {
          // try next
        }
      }
      // Final attempt on the class itself (covers non-proxy cases in tests).
      return cls.getMethod(methodName);
    }
  }
}

